#include <gtest/gtest.h>

#include "solvers/chain.h"

TEST(TestChain, AICType2) {
    // 5 5- r2c2 -9- r8c2 =9= r8c9 =1= r8c3 -1- r2c3 -8- r2c5 =8= r8c5 -8- r8c8
    // -5 => r2c8,r8c2<>5
    Inst inst = {0xD1,  // type
                 6,     // length
                 0x88, 0x00, 0x78, 0x00, 0x72, 0x00, 0x72,
                 0x03, 0x76, 0x03, 0x76, 0x06, 0x88, 0x06};
    std::vector<uint16_t> executees = {0x8806};
    Grid grid(
        "0000001110100000011100100000010001000001000011101300000000000000001011"
        "1011000000000000010011000000000011100000100010101000000010001000100000"
        "0100000100001110000000101100160000000000000010001000000110100000140000"
        "0000000000001110000200000000001300000000001100000000000000011010000000"
        "0110100018000000000019000000000000000011100000010100000013000000000016"
        "0000000000150000000000010000000000000001000100190000000000170000000000"
        "0001000001000800000000000100000000001500000000000000000010101200000000"
        "0000000000101016000000000004000000000003000000000000010100000017000000"
        "0000190000000000000001000100060000000000130000000000150000000000110000"
        "0000000001000001000000001100101800000000001700000000000000110000000000"
        "0110000011000000000012000000000000001011000000000011001013000000000000"
        "0001100010001001000000160000000000000000101100020000000000000001001000"
        "0000001001000010001010100010001100000000011100001200000000000000100011"
        "00190000000000000000101100000011001000000010110100001000101000");
    findAIC(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

