TEST(TestChain, CNL1) {
    Inst inst = {
        0xc2,  // type
        8,     // length
        0x55, 0x01, 0x65, 0x01, 0x65, 0x04, 0x75, 0x04,
        0x75, 0x02, 0x74, 0x02, 0x34, 0x02, 0x34, 0x01,  // chain
        0x14, 0x02, 0x33, 0x01, 0x53, 0x01, 0x54, 0x01,
        0x54, 0x02, 0x65, 0x05, 0x65, 0x07, 0x75, 0x07  // executees
    };
    std::vector<uint16_t> executees = {0x1402, 0x3301, 0x5301, 0x5401,
                                       0x5402, 0x6505, 0x6507, 0x7507};
    Grid grid(
        "0000101001100400000000000000101001100000100011001600000000000000100001"
        "1011000000000000000010100002000000000000101000010012000000000017000000"
        "0000150000000000001010000100000010000100040000000000090000000000160000"
        "0000000010001100100000001000100000001100100011000010000011000010101400"
        "0000000013000000000000000010100018000000000014000000000001000000000000"
        "0110010000000110010000000110000000170000000000190000000000180000000000"
        "0500000000000000100111100000000011100000100101100000110101001500000000"
        "0000001001011012000000000000001100000011000000000000011010011000000010"
        "0110000110100110001111000100001111000110000110000110060000000000000011"
        "0000000700000000000001001011100000001011101400000000000001000111000001"
        "0000110000010011010000000010110001000000000003000000000000000010110016"
        "0000000000110000000000190000000000000010001100000010100100000000101100"
        "1200000000001400000000000001001011001300000000000001001001000001010011"
        "00000101001100110000000000000000101100060000000000090000000000");
    findNiceLoop(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getInst()->size(), inst.size());
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

