    std::vector<uint16_t> executees = {0x0107};
    Grid grid(
        "0001100001000001010101000001100101000000110100100000100100101500000000"
        "0000011100001011000000000017000000000019000000000011000000000000001001"
        "0000000011010000170000000000120000000000150000000000000011000100000010"
        "0101000500000000000001010110000001100110001800000000001100000000000000"
        "1101001000011101001000011100001000011001000000010000110013000000000015"
        "0000000000000101000010000100000010000001000110000100001010160000000000"
        "1100000000001100000000000001000011000001000011000001100100101500000000"
        "0000001001011000011000101000011000001014000000000016000000000019000000"
        "0000040000000000010000000000000110000000070000000000180000000000150000"
        "0000000001100000000001100010000001000110000001100110100001100100101800"
        "0000000011000000000000011101000000011100000005000000000000011000010000"
        "0100010100110000000000150000000000140000000000000010010000000110010000"
        "1700000000001900000000001400000000001500000000000001100100101700000000"
        "00000110010010000010010010010000000000000110000100000110010100");
