TEST(TestChain, DNL2) {
    // Discontinuous Nice Loop: 1 r5c1 -1- r8c1 -7- r8c6 =7= r7c6 =4= r4c6 -4-
    // r4c1 =4= r5c1 => r5c1<>1
    Inst inst = {0xd1,  // type
                 8,    0x70, 0x00, 0x70, 0x06, 0x75, 0x06, 0x65, 0x06,
                 0x65, 0x03, 0x35, 0x03, 0x30, 0x03, 0x40, 0x03,

                 0x40, 0x00};
    std::vector<uint16_t> executees = {0x4000};
    Grid grid(
        "1200000000001600000000000000000011000900000000001400000000000010100001"
        "0000100010100000001010110000101010010000001010110000001010110011000000"
        "0000000000001100000010110000120000000000190000000000000011001100000011"
        "0101000000101011001400000000001900000000000010000011000010101100000010"
        "1001010000100000100000011000110000111001010000100100001000100000001002"
        "0000000000160000000000170000000000001001000000180000000000000010100000"
        "0000101000000010010011000010000011001500000000001300000000000011000000"
        "0019000000000016000000000000010100100000110100000006000000000000100000"
        "1000130000000000001101000000180000000000150000000000001001001000000101"
        "0010100011010000100000101011100010101011100000000011000010010001000010"
        "1000000000101100110012000000000016000000000000000110000000100000100000"
        "1100001000140000000000150000000000001100010000001000011000130000000000"
        "0000000001100000000001100000101001000001101001000600000000000001010001"
        "00190000000000000010000100000001100000110000000000170000000000");
    findAIC(grid);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

